          {totalVol24h > 0 && (
            <span>
              24h Vol:{' '}
              <span className="text-zinc-300">
                {formatVolume(totalVol24h)}
              </span>
            </span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {lastUpdate && (
            <span>
              Updated{' '}
