import { useState, useEffect, useCallback, useRef } from "react";
import { KalshiMarket } from "../types";

const KALSHI_API = "https://api.elections.kalshi.com/trade-api/v2";

export function useKalshiMarkets(pollInterval = 30000) {
  const [markets, setMarkets] = useState<KalshiMarket[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [debugInfo, setDebugInfo] = useState<string>("");
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const fetchMarkets = useCallback(async (isInitial = false) => {
    if (isInitial) setLoading(true);
    setError(null);

    if (abortRef.current) abortRef.current.abort();
    const controller = new AbortController();
    abortRef.current = controller;

    try {
      const apiUrl = `${KALSHI_API}/markets?status=open&limit=200`;
      const proxyUrl = `/api/proxy?url=${encodeURIComponent(apiUrl)}`;

      setDebugInfo(`Fetching: ${proxyUrl}`);

      const res = await fetch(proxyUrl, {
        signal: controller.signal,
        headers: {
          "Accept": "application/json",
        },
      });

      if (!res.ok) {
        const text = await res.text().catch(() => "");
        throw new Error(`HTTP ${res.status}: ${text.slice(0, 200)}`);
      }

      const text = await res.text();

      if (!text || text.trim().length === 0) {
        throw new Error("Empty response body");
      }

      let data: any;
      try {
        data = JSON.parse(text);
      } catch {
        throw new Error(`Invalid JSON response: ${text.slice(0, 200)}`);
      }

      // Handle various possible response shapes
      const marketsArray = data.markets || data.data?.markets || [];

      if (!Array.isArray(marketsArray)) {
        setDebugInfo(`Response keys: ${Object.keys(data).join(", ")} | Type of markets: ${typeof data.markets}`);
        throw new Error(`Unexpected response shape. Keys: ${Object.keys(data).join(", ")}`);
      }

      // Sort by 24h volume descending
      const sorted = marketsArray
        .sort((a: KalshiMarket, b: KalshiMarket) => {
          const volA = parseFloat(a.volume_24h_fp || a.volume_24h || "0");
          const volB = parseFloat(b.volume_24h_fp || b.volume_24h || "0");
          return volB - volA;
        });

      setMarkets(sorted);
      setLastUpdated(new Date());
      setDebugInfo(`Loaded ${sorted.length} markets`);
    } catch (err: any) {
      if (err.name !== "AbortError") {
        setError(err.message || "Failed to fetch markets");
        setDebugInfo(`Error: ${err.message}`);
      }
    } finally {
      if (isInitial) setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchMarkets(true);
    const interval = setInterval(() => fetchMarkets(false), pollInterval);
    return () => {
      clearInterval(interval);
      if (abortRef.current) abortRef.current.abort();
    };
  }, [fetchMarkets, pollInterval]);

  return {
    markets,
    loading,
    error,
    debugInfo,
    lastUpdated,
    refresh: () => fetchMarkets(true),
  };
}

