import React from "react";
import { KalshiMarket } from "../types";
import { TrendingUp, TrendingDown, Minus } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { TableRow, TableCell } from "@/components/ui/table";
import { formatDistanceToNow } from "date-fns";

function parseDollarToCents(val: string | number | undefined): number {
  if (val === undefined || val === null) return 0;
  if (typeof val === "number") return val; // might already be cents
  const num = parseFloat(val);
  if (isNaN(num)) return 0;
  // If value is like "0.56" (dollars), convert to cents
  if (num > 0 && num <= 1) return Math.round(num * 100);
  // If value is already in cents range
  return Math.round(num);
}

function formatCents(cents: number): string {
  if (cents <= 0) return "—";
  return `${cents}¢`;
}

function formatVolume(val: string | number | undefined): string {
  if (!val) return "0";
  const num = typeof val === "number" ? val : parseFloat(val);
  if (isNaN(num)) return "0";
  if (num >= 1_000_000) return `${(num / 1_000_000).toFixed(1)}M`;
  if (num >= 1_000) return `${(num / 1_000).toFixed(1)}K`;
  return num.toFixed(0);
}

function getPriceColor(cents: number): string {
  if (cents >= 70) return "text-emerald-400";
  if (cents >= 40) return "text-yellow-400";
  if (cents <= 0) return "text-zinc-600";
  return "text-red-400";
}

function getPriceChangeIcon(current: string | undefined, previous: string | undefined) {
  const curr = parseFloat(current || "0");
  const prev = parseFloat(previous || "0");
  if (curr > prev && prev > 0) return <TrendingUp className="w-3 h-3 text-emerald-400" />;
  if (curr < prev && prev > 0) return <TrendingDown className="w-3 h-3 text-red-400" />;
  return <Minus className="w-3 h-3 text-zinc-600" />;
}

interface MarketRowProps {
  market: KalshiMarket;
}

export const MarketRow: React.FC<MarketRowProps> = ({ market }) => {
  const yesBidCents = parseDollarToCents(market.yes_bid_dollars);
  const yesAskCents = parseDollarToCents(market.yes_ask_dollars);
  const lastPriceCents = parseDollarToCents(market.last_price_dollars);
  const midPrice = yesBidCents && yesAskCents
    ? (yesBidCents + yesAskCents) / 2
    : lastPriceCents || yesBidCents || yesAskCents;

  let closesIn = "—";
  try {
    if (market.close_time) {
      closesIn = formatDistanceToNow(new Date(market.close_time), { addSuffix: false });
    }
  } catch {
    closesIn = "—";
  }

  return (
    <TableRow className="hover:bg-zinc-800/50 border-zinc-800/60 transition-colors">
      <TableCell className="max-w-[320px] py-2">
        <div className="flex flex-col gap-0.5">
          <span
            className="text-zinc-100 text-xs font-medium leading-tight truncate"
            title={market.title}
          >
            {market.title}
          </span>
          <div className="flex items-center gap-1.5">
            <Badge
              variant="outline"
              className="text-[10px] px-1 py-0 border-zinc-700 text-zinc-500 font-normal h-4"
            >
              {market.ticker}
            </Badge>
            <span className="text-[10px] text-zinc-600">closes {closesIn}</span>
          </div>
        </div>
      </TableCell>
      <TableCell className="text-right py-2">
        <div className="flex items-center justify-end gap-1">
          {getPriceChangeIcon(market.yes_bid_dollars, market.previous_yes_bid_dollars)}
          <span className={`text-xs font-medium ${getPriceColor(yesBidCents)}`}>
            {formatCents(yesBidCents)}
          </span>
        </div>
      </TableCell>
      <TableCell className="text-right py-2">
        <span className={`text-xs font-medium ${getPriceColor(yesAskCents)}`}>
          {formatCents(yesAskCents)}
        </span>
      </TableCell>
      <TableCell className="text-right py-2">
        <span className={`text-xs font-medium ${getPriceColor(lastPriceCents)}`}>
          {formatCents(lastPriceCents)}
        </span>
      </TableCell>
      <TableCell className="text-right py-2">
        <div className="flex flex-col items-end">
          <span className="text-xs text-zinc-300 font-medium">
            {formatVolume(market.volume_24h_fp || market.volume_24h)}
          </span>
          <span className="text-[10px] text-zinc-600">
            {formatVolume(market.volume_fp || market.volume)} total
          </span>
        </div>
      </TableCell>
      <TableCell className="text-right py-2">
        <span className="text-xs text-zinc-400">
          {formatVolume(market.open_interest_fp || market.open_interest)}
        </span>
      </TableCell>
      <TableCell className="text-center py-2">
        <div className="flex items-center gap-1.5">
          <div
            className="flex-1 h-1.5 bg-zinc-800 overflow-hidden"
            title={`${midPrice.toFixed(0)}% YES`}
          >
            <div
              className="h-full bg-gradient-to-r from-emerald-500 to-emerald-400 transition-all duration-500"
              style={{ width: `${Math.min(Math.max(midPrice, 2), 98)}%` }}
            />
          </div>
          <span className="text-[10px] text-zinc-500 w-7 text-right">{midPrice.toFixed(0)}%</span>
        </div>
      </TableCell>
    </TableRow>
  );
};

