      {error && (
        <div className="px-4 pb-2">
          <Alert variant="destructive" className="py-2">
            <AlertCircle className="w-3 h-3" />
            <AlertDescription className="text-xs">{error}</AlertDescription>
          </Alert>
        </div>
      )}

      {/* Content */}
      <ScrollArea className="flex-1 px-4">
        {loading ? (
          <div className="space-y-3 pb-4">
            {Array.from({ length: 8 }).map((_, i) => (
              <div key={i} className="bg-zinc-900 border border-zinc-800 p-3">
                <div className="flex gap-3">
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-3/4 bg-zinc-800" />
                    <Skeleton className="h-3 w-1/2 bg-zinc-800" />
                  </div>
                  <Skeleton className="w-12 h-8 bg-zinc-800" />
                </div>
                <Skeleton className="h-5 w-full mt-2 bg-zinc-800" />
              </div>
            ))}
          </div>
        ) : filtered.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-16 text-zinc-500">
            <Search className="w-8 h-8 mb-3 text-zinc-600" />
            <p className="text-sm">No markets found</p>
            <p className="text-xs mt-1">
              {search
                ? 'Try a different search term'
                : 'No active markets in this category'}
            </p>
          </div>
        ) : (
          <AnimatePresence mode="popLayout">
            <div className="space-y-2 pb-4">
              {filtered.map((event, i) => (
                <motion.div
                  key={event.event_ticker}
                  layout
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  exit={{ opacity: 0, y: -10 }}
                  transition={{ duration: 0.2, delay: i * 0.02 }}
                >
                  <EventCard event={event} />
                </motion.div>
              ))}
            </div>
          </AnimatePresence>
        )}
      </ScrollArea>
    </div>
  );
}

export default App;

