import { ProcessedEvent } from '../types';
import { formatVolume } from '../lib/api';
import { TrendingUp, TrendingDown, BarChart3, Activity, Target } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { motion } from 'framer-motion';

function parseDollarsToCents(dollars: string | undefined | null): number {
  if (!dollars) return 0;
  const val = parseFloat(dollars);
  if (isNaN(val)) return 0;
  return Math.round(val * 100);
}

function getPriceColor(cents: number): string {
  if (cents >= 75) return '#34d399';
  if (cents >= 50) return '#fbbf24';
  if (cents >= 25) return '#fb923c';
  return '#f87171';
}

function getBarColor(cents: number): string {
  if (cents >= 75) return '#34d399';
  if (cents >= 50) return '#60a5fa';
  if (cents >= 25) return '#fb923c';
  return '#f87171';
}

export default function EventCard({ event }: { event: ProcessedEvent }) {
  const { featuredMarket, markets } = event;
  const yesPrice = event.yesPrice;
  const prevPrice = event.previousPrice;
  const trending = yesPrice > prevPrice ? 'up' : yesPrice < prevPrice ? 'down' : 'flat';

  const featuredTitle = featuredMarket.yes_sub_title || featuredMarket.subtitle || featuredMarket.title;
  const shortLabel = featuredTitle.length <= 16 ? featuredTitle : 'Yes';

  const otherMarkets = markets.filter(m => m.ticker !== featuredMarket.ticker);
  const showMarkets = otherMarkets.slice(0, 3);
  const moreCount = otherMarkets.length - showMarkets.length;

  const categoryLabel = event.category.charAt(0).toUpperCase() + event.category.slice(1);

  return (
    <motion.div
      className="bg-zinc-900 border border-zinc-800 p-3 hover:border-zinc-600 transition-colors cursor-pointer group"
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
    >
      {/* Header */}
      <div className="flex gap-3">
        <div className="flex-1 min-w-0">
          <h3 className="text-sm font-semibold text-zinc-100 leading-tight line-clamp-2 group-hover:text-white">
            {event.title}
          </h3>

          <div className="flex items-center gap-3 mt-1.5 text-[11px] text-zinc-500">
            <span className="flex items-center gap-1">
              <BarChart3 className="w-3 h-3" />
              Vol {formatVolume(event.totalVolume)}
            </span>
            <span className="flex items-center gap-1">
              <Activity className="w-3 h-3" />
              24h {formatVolume(event.totalVolume24h)}
            </span>
            <span className="flex items-center gap-1">
              <Target className="w-3 h-3" />
              OI {formatVolume(event.totalOI)}
            </span>
          </div>
        </div>

        <div className="shrink-0 text-right">
          <div
            className="text-lg font-bold"
            style={{ color: getPriceColor(yesPrice) }}
          >
            {yesPrice}%
          </div>
          <div className="text-[10px] text-zinc-500 uppercase">
            {shortLabel}
          </div>
        </div>
      </div>

      {/* Price Bar */}
      <div className="mt-2.5 space-y-1">
        <div className="flex items-center gap-2 text-xs">
          <span className="w-16 truncate text-zinc-400 shrink-0">{shortLabel}</span>
          <div className="flex-1 h-5 bg-zinc-800 relative overflow-hidden">
            <motion.div
              className="h-full absolute left-0 top-0"
              style={{ backgroundColor: getBarColor(yesPrice) }}
              initial={{ width: 0 }}
              animate={{ width: `${Math.max(yesPrice, 5)}%` }}
              transition={{ duration: 0.6, ease: 'easeOut' }}
            />
            <span className="absolute inset-0 flex items-center justify-center text-white font-bold text-[11px] z-10">
              {yesPrice}¢
            </span>
          </div>
          {trending === 'up' && <TrendingUp className="w-3 h-3 text-emerald-400 shrink-0" />}
          {trending === 'down' && <TrendingDown className="w-3 h-3 text-red-400 shrink-0" />}
        </div>
      </div>

      {/* Sub-markets */}
      {otherMarkets.length > 0 && (
        <div className="mt-2 flex items-center gap-1.5 flex-wrap">
          {showMarkets.map((m) => {
            const price = parseDollarsToCents(m.last_price_dollars) || parseDollarsToCents(m.yes_bid_dollars) || (m.yes_price ?? 0);
            return (
              <Badge
                key={m.ticker}
                variant="secondary"
                className="text-[10px] bg-zinc-800 text-zinc-400 border-zinc-700 px-1.5 py-0 font-normal max-w-[180px] truncate"
              >
                {m.title?.slice(0, 40)}
                {price ? ` · ${price}¢` : ''}
              </Badge>
            );
          })}
          {moreCount > 0 && (
            <Badge
              variant="outline"
              className="text-[10px] text-zinc-500 border-zinc-700 px-1.5 py-0"
            >
              +{moreCount} more
            </Badge>
          )}
        </div>
      )}

      {/* Tags */}
      <div className="mt-2 flex gap-1 flex-wrap">
        <span className="text-[10px] px-1.5 py-0.5 bg-zinc-800/50 text-zinc-500 border border-zinc-800">
          {categoryLabel}
        </span>
        {event.series_ticker && (
          <span className="text-[10px] px-1.5 py-0.5 bg-zinc-800/50 text-zinc-500 border border-zinc-800 font-mono">
            {event.series_ticker}
          </span>
        )}
      </div>
    </motion.div>
  );
}
